import{_ as a,o as e,c as l,ag as i}from"./chunks/framework.DEs8X8sU.js";const u=JSON.parse('{"title":"テーブル開放認証","description":"","frontmatter":{"title":"テーブル開放認証"},"headers":[],"relativePath":"tenant/25-table-auth.md","filePath":"tenant/25-table-auth.md"}'),r={name:"tenant/25-table-auth.md"};function d(o,t,n,h,s,_){return e(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="_25-テーブル開放認証" tabindex="-1">25. テーブル開放認証 <a class="header-anchor" href="#_25-テーブル開放認証" aria-label="Permalink to &quot;25. テーブル開放認証&quot;">​</a></h1><p>テーブル開放認証は、お客様がQRコードから注文する前に、対象テーブルが利用可能な状態か確認する仕組みです。誤注文やいたずら注文を防ぐために利用します。</p><h2 id="基本の考え方" tabindex="-1">基本の考え方 <a class="header-anchor" href="#基本の考え方" aria-label="Permalink to &quot;基本の考え方&quot;">​</a></h2><ul><li>お客様が着席したら、店舗側でテーブルを利用可能にします。</li><li>お客様は該当テーブルのQRコードから注文します。</li><li>退店後は会計完了と片付けを確認し、テーブルを終了します。</li></ul><h2 id="営業中の流れ" tabindex="-1">営業中の流れ <a class="header-anchor" href="#営業中の流れ" aria-label="Permalink to &quot;営業中の流れ&quot;">​</a></h2><ol><li>お客様を席へ案内します。</li><li>必要に応じてテーブルを開放します。</li><li>お客様がQRコードから注文します。</li><li>会計完了後、テーブルを終了します。</li><li>次のお客様用に状態を整えます。</li></ol><h2 id="注意点" tabindex="-1">注意点 <a class="header-anchor" href="#注意点" aria-label="Permalink to &quot;注意点&quot;">​</a></h2><ul><li>QRコードの貼り間違いに注意してください。</li><li>テーブル終了を忘れると、次のお客様の注文と混ざる可能性があります。</li><li>予約来店の場合は、予約情報とテーブル状態を確認してください。</li></ul><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>お客様が注文画面に進めない</td><td>テーブルが開放されているか確認してください。</td></tr><tr><td>別テーブルの画面が開く</td><td>QRコードの貼り間違いを確認してください。</td></tr><tr><td>前のお客様の情報が残る</td><td>会計完了とテーブル終了を確認してください。</td></tr><tr><td>予約と自動で合わない</td><td>予約日時、人数、テーブル状態を確認してください。</td></tr></tbody></table>',10)])])}const b=a(r,[["render",d]]);export{u as __pageData,b as default};
